Double-Tap Text Selection Solution

After some exploration, I found a workaround to achieve text selection on double-tap in the `EditableText` widget. This solution involves using the `GestureDetector` to detect double-tap events and then programmatically selecting all text
and property of  selectionColor and showSelectionHandles

Here's the updated code:
````
import 'package:flutter/material.dart';

const Color darkBlue = Color.fromARGB(255, 18, 32, 47);

void main() {
  runApp(MyApp());
}

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      theme: ThemeData.light().copyWith(),
      debugShowCheckedModeBanner: false,
      home: Scaffold(
        body: Center(
          child: MyWidget(),
        ),
      ),
    );
  }
}

final controller = TextEditingController(text: 'hello world');
final focusNode = FocusNode();

class MyWidget extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return GestureDetector(
      onDoubleTap: () {
        // Select all text when double-tapped
        final newText = controller.text;
        controller.value = controller.value.copyWith(
          selection: TextSelection(
            baseOffset: 0,
            extentOffset: newText.length,
          ),
        );
        focusNode.requestFocus();
      },
      child: EditableText(
        selectionColor: Colors.black38,
        controller: controller,
        focusNode: focusNode,
        backgroundCursorColor: Colors.yellow,
        showSelectionHandles: true,
        cursorColor: Colors.red,
        style: const TextStyle(),
      ),
    );
  }
}
`
